document.addEventListener("DOMContentLoaded",function(){document.querySelectorAll("[data-include]").forEach(function(t){var e=t.getAttribute("data-include");e&&-1===e.indexOf("/partials/header.html")&&-1===e.indexOf("/partials/footer.html")&&fetch(e,{cache:"no-store"}).then(function(t){if(!t.ok)throw new Error("No se pudo cargar "+e);return t.text()}).then(function(e){t.innerHTML=e}).catch(function(t){console.warn("Error en data-include ("+e+"):",t)})})});